export function debounceAsync<A extends unknown[], R>(
  fn: (...args: A) => Promise<R> | R,
  delay: number
) {
  let timer: ReturnType<typeof setTimeout> | undefined;
  let lastId = 0;
  let pending:
    | { id: number; args: A; resolve: (v: R) => void; reject: (e: any) => void }
    | null = null;

  const stale = (cause?: any) => Object.assign(new Error("stale"), { cause });

  const run = async () => {
    const job = pending;
    if (!job) return;
    pending = null;
    const myId = job.id;
    try {
      const value = await fn(...job.args);
      if (myId !== lastId) job.reject(stale());
      else job.resolve(value as R);
    } catch (err) {
      if (myId !== lastId) job.reject(stale(err));
      else job.reject(err);
    }
  };

  return (...args: A): Promise<R> => {
    lastId++;
    if (timer) clearTimeout(timer);
    if (pending) pending.reject(stale());
    return new Promise<R>((resolve, reject) => {
      pending = { id: lastId, args, resolve, reject };
      timer = setTimeout(run, delay);
    });
  };
}

